using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Configure options with a default type resolver so common types are known.
var options = new JsonSerializerOptions
{
    TypeInfoResolver = JsonSerializerOptions.Default.TypeInfoResolver
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly.
JsonTypeInfo<int[]> arrayInfo = (JsonTypeInfo<int[]>)options.GetTypeInfo(typeof(int[]));
Console.WriteLine($"Got typed metadata for int[]: {arrayInfo.Type}");

// 2) Non-throwing probe with TryGetTypeInfo — returns false if metadata unavailable.
bool found = options.TryGetTypeInfo(typeof(string), out JsonTypeInfo? stringInfo);
Console.WriteLine($"Probe string: found={found}, type={stringInfo?.Type}");

// Probe for a type that has NO metadata registered (use a custom resolver that knows nothing).
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};
// DefaultJsonTypeInfoResolver can resolve anything it can reflect over,
// so use an empty custom resolver to simulate "not available".
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = JsonSerializer.IsReflectionEnabledByDefault
        ? new EmptyResolver()
        : new EmptyResolver()
};

bool foundWidget = empty.TryGetTypeInfo(typeof(Widget), out JsonTypeInfo? widgetInfo);
Console.WriteLine($"Probe Widget on empty resolver: found={foundWidget}, info={widgetInfo?.Type}");

Console.WriteLine("Done.");

record Widget(string Name);

// A resolver that resolves nothing — simulates missing metadata.
sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

